import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionVulnerable {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter the name of the file: ");
        String fileName = br.readLine();

        // Vulnerable code - user input is directly passed to the command without proper validation or sanitization
        String command = "ls " + fileName;

        Process p = Runtime.getRuntime().exec(command);
        BufferedReader commandOutput = new BufferedReader(new InputStreamReader(p.getInputStream()));

        String line;
        while ((line = commandOutput.readLine()) != null) {
            System.out.println(line);
        }
    }
}

