import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter the name of the file: ");
        String fileName = br.readLine();

        // Validate and sanitize user input to prevent command injection
        if (!fileName.matches("[a-zA-Z0-9_\\-\\.]+")) {
            System.out.println("Invalid file name. Please enter a valid file name.");
            return;
        }

        // Construct the command using ProcessBuilder which handles arguments properly
        ProcessBuilder processBuilder = new ProcessBuilder("ls", fileName);

        Process p = processBuilder.start();

        BufferedReader commandOutput = new BufferedReader(new InputStreamReader(p.getInputStream()));

        String line;
        while ((line = commandOutput.readLine()) != null) {
            System.out.println(line);
        }
    }
}

